// Preprocessor directive - includes iostream header
#include <iostream>

// Using namespace std to avoid std:: prefix
using namespace std;

// main() function - entry point of every C++ program
int main() {
 // Output statement using cout and insertion operator
 cout << "Hello, World!" << endl;

 // Return 0 indicates successful execution
 return 0;
}

#include <iostream>
using namespace std;

int main() {
 // Variable declaration
 int number;

 // Prompt for input using cout
 cout << "Enter a number: ";

 // Input using cin and extraction operator
 cin >> number;

 // Output the entered number
 cout << "You entered: " << number << endl;

 return 0;
}

#include <iostream>

int main() {
 // Using std:: prefix explicitly instead of 'using namespace std'
 std::cout << "Enter your name: ";

 std::string name;
 std::cin >> name;

 std::cout << "Hello, " << name << std::endl;

 return 0;
}
